// Define props with a TypeScript interface
interface UserCardProps {
  name: string;
  email: string;
  avatar?: string;        // Optional
  onFollow?: () => void;  // Optional callback
  children?: React.ReactNode; // Optional nested content
}

function UserCard({ name, email, avatar, onFollow, children }: UserCardProps) {
  return (
    <div className="card">
      {avatar && <img src={avatar} alt={`${name}'s avatar`} />}
      <h3>{name}</h3>
      <p>{email}</p>
      {children}
      {onFollow && <button onClick={onFollow}>Follow</button>}
    </div>
  );
}

// Usage
function App() {
  return (
    <div>
      <UserCard name="Alice" email="alice@example.com" />

      <UserCard
        name="Bob"
        email="bob@example.com"
        avatar="/bob.jpg"
        onFollow={() => console.log('Followed Bob!')}
      >
        <p>Bob is a software engineer.</p>
      </UserCard>
    </div>
  );
}
